import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import './RolePlay.css';

const MOCK_STORIES = [
  { id:1, emoji:'🍜', title:'Restaurant Conversation', category:'Daily Life', jlpt:'N5', characters:2, dialogue:6,  difficulty:'Easy',   status:'published', date:'2026-07-10' },
  { id:2, emoji:'🏥', title:'Hospital Visit',          category:'Healthcare',  jlpt:'N4', characters:3, dialogue:8,  difficulty:'Medium', status:'published', date:'2026-07-11' },
  { id:3, emoji:'✈️',  title:'Airport Check-In',        category:'Travel',      jlpt:'N3', characters:4, dialogue:12, difficulty:'Hard',   status:'published', date:'2026-07-12' },
  { id:4, emoji:'🏨', title:'Hotel Reception',          category:'Travel',      jlpt:'N4', characters:2, dialogue:7,  difficulty:'Medium', status:'draft',     date:'2026-07-13' },
  { id:5, emoji:'🏫', title:'School Introduction',      category:'Education',   jlpt:'N5', characters:3, dialogue:9,  difficulty:'Easy',   status:'published', date:'2026-07-14' },
  { id:6, emoji:'🛍️',  title:'Shopping Mall',           category:'Daily Life',  jlpt:'N5', characters:2, dialogue:5,  difficulty:'Easy',   status:'draft',     date:'2026-07-15' },
  { id:7, emoji:'💼', title:'Office Meeting',           category:'Business',    jlpt:'N3', characters:4, dialogue:14, difficulty:'Hard',   status:'published', date:'2026-07-16' },
  { id:8, emoji:'🚄', title:'Train Station',            category:'Travel',      jlpt:'N4', characters:3, dialogue:8,  difficulty:'Medium', status:'published', date:'2026-07-17' },
  { id:9, emoji:'☕', title:'Cafe Order',               category:'Daily Life',  jlpt:'N5', characters:2, dialogue:4,  difficulty:'Easy',   status:'draft',     date:'2026-07-17' },
  { id:10,emoji:'🎉', title:'Summer Festival',          category:'Culture',     jlpt:'N3', characters:5, dialogue:18, difficulty:'Hard',   status:'published', date:'2026-07-18' },
];

const CATEGORIES = ['All','Daily Life','Healthcare','Travel','Education','Business','Culture'];
const JLPT_LEVELS = ['All','N5','N4','N3','N2','N1'];
const STATUSES = ['All','published','draft'];

export default function RolePlayStories() {
  const navigate = useNavigate();
  const [search, setSearch] = useState('');
  const [catFilter, setCatFilter] = useState('All');
  const [jlptFilter, setJlptFilter] = useState('All');
  const [statusFilter, setStatusFilter] = useState('All');
  const [stories, setStories] = useState(MOCK_STORIES);

  const filtered = stories.filter(s =>
    (catFilter === 'All' || s.category === catFilter) &&
    (jlptFilter === 'All' || s.jlpt === jlptFilter) &&
    (statusFilter === 'All' || s.status === statusFilter) &&
    (search === '' || s.title.toLowerCase().includes(search.toLowerCase()))
  );

  const handleDelete = (id) => {
    if (window.confirm('Delete this story?')) {
      setStories(prev => prev.filter(s => s.id !== id));
    }
  };

  const handleDuplicate = (story) => {
    const dup = { ...story, id: Date.now(), title: story.title + ' (Copy)', status: 'draft' };
    setStories(prev => [...prev, dup]);
  };

  const toggleStatus = (id) => {
    setStories(prev => prev.map(s =>
      s.id === id ? { ...s, status: s.status === 'published' ? 'draft' : 'published' } : s
    ));
  };

  return (
    <div className="rp-page">
      <div className="rp-page-header">
        <div>
          <h2 className="rp-page-title">📖 Stories</h2>
          <p className="rp-page-sub">Manage all RolePlay conversation stories.</p>
        </div>
        <div className="rp-header-actions">
          <button className="btn btn-secondary" onClick={() => navigate('/roleplay/import')}>
            📊 Import Excel
          </button>
          <button className="btn btn-primary" onClick={() => navigate('/roleplay/stories/new')}>
            + Add Story
          </button>
        </div>
      </div>

      {/* Filters */}
      <div className="rp-filters">
        <input
          className="rp-search"
          placeholder="🔍 Search stories..."
          value={search}
          onChange={e => setSearch(e.target.value)}
        />
        <select className="rp-select" value={catFilter} onChange={e => setCatFilter(e.target.value)}>
          {CATEGORIES.map(c => <option key={c}>{c}</option>)}
        </select>
        <select className="rp-select" value={jlptFilter} onChange={e => setJlptFilter(e.target.value)}>
          {JLPT_LEVELS.map(l => <option key={l}>{l}</option>)}
        </select>
        <select className="rp-select" value={statusFilter} onChange={e => setStatusFilter(e.target.value)}>
          {STATUSES.map(s => <option key={s} value={s}>{s === 'All' ? 'All Status' : s.charAt(0).toUpperCase() + s.slice(1)}</option>)}
        </select>
      </div>

      {/* Table */}
      <div className="card" style={{ padding: 0 }}>
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Cover</th>
                <th>Title</th>
                <th>Category</th>
                <th>JLPT</th>
                <th>Chars</th>
                <th>Dialogue</th>
                <th>Difficulty</th>
                <th>Status</th>
                <th>Date</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map(s => (
                <tr key={s.id}>
                  <td>
                    <div className="rp-cover-cell">{s.emoji}</div>
                  </td>
                  <td style={{ fontWeight: 700 }}>{s.title}</td>
                  <td><span className="badge badge-blue">{s.category}</span></td>
                  <td><span className="rp-jlpt-badge">{s.jlpt}</span></td>
                  <td>{s.characters}</td>
                  <td>{s.dialogue}</td>
                  <td>
                    <span className={`badge ${s.difficulty === 'Easy' ? 'badge-green' : s.difficulty === 'Medium' ? 'badge-blue' : 'badge-red'}`}>
                      {s.difficulty}
                    </span>
                  </td>
                  <td>
                    <button
                      className={`rp-status-toggle ${s.status === 'published' ? 'published' : 'draft'}`}
                      onClick={() => toggleStatus(s.id)}
                    >
                      {s.status === 'published' ? '● Published' : '○ Draft'}
                    </button>
                  </td>
                  <td style={{ color: 'var(--text-muted)', fontSize: 12 }}>{s.date}</td>
                  <td>
                    <div className="rp-action-row">
                      <button className="btn btn-icon" title="Preview">👁</button>
                      <button className="btn btn-icon" title="Edit">✏️</button>
                      <button className="btn btn-icon" title="Duplicate" onClick={() => handleDuplicate(s)}>⧉</button>
                      <button className="btn btn-icon btn-danger" title="Delete" onClick={() => handleDelete(s.id)}>🗑</button>
                    </div>
                  </td>
                </tr>
              ))}
              {filtered.length === 0 && (
                <tr>
                  <td colSpan={10} style={{ textAlign: 'center', padding: 32, color: 'var(--text-muted)' }}>
                    No stories found. Try adjusting your filters.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="rp-table-footer">
        Showing {filtered.length} of {stories.length} stories
      </div>
    </div>
  );
}
